def _resolve_repo_config_path():
    return Path(__file__).resolve().parents[1] / "config" / "config.yaml"


def _resolve_platform_stream_symbols(config):
    raw_symbols = None
    if isinstance(config, dict):
        raw_symbols = config.get("symbols")
        if raw_symbols in (None, "", []):
            raw_symbols = config.get("symbol")
    if isinstance(raw_symbols, str):
        return [part.strip() for part in raw_symbols.split(",") if part.strip()]
    if isinstance(raw_symbols, (list, tuple, set)):
        return [str(symbol).strip() for symbol in raw_symbols if str(symbol).strip()]
    if raw_symbols is None:
        return []
    text = str(raw_symbols).strip()
    return [text] if text else []


def _should_auto_start_platform_stream(simulate=False):
    if not _env_flag("ZOL0_PLATFORM_STREAM_AUTO_START"):
        return False
    bot_mode = str(os.environ.get("BOT_MODE", "")).strip().lower()
    return bool(simulate or bot_mode in {"paper", "live-paper"})


def _start_runtime_platform_stream(
    config,
    *,
    simulate=False,
    logger=None,
    manager_factory=None,
):
    if not _should_auto_start_platform_stream(simulate=simulate):
        return None

    symbols = _resolve_platform_stream_symbols(config)
    if not symbols:
        if logger is not None:
            logger.warning(
                "BotCore: platform stream auto-start skipped because symbols are empty"
            )
        return None

    market_type = ""
    if isinstance(config, dict):
        market_type = str(config.get("market_type") or "").strip().lower()
    if not market_type:
        market_type = str(os.environ.get("MARKET_TYPE", "")).strip().lower()
    if market_type not in {"spot", "futures"}:
        market_type = (
            "futures"
            if any(str(symbol).upper().endswith("USDTM") for symbol in symbols)
            else None
        )

    try:
        manager_cls = manager_factory
        if manager_cls is None:
            from platforms.MetaPlatformManager import MetaPlatformManager as manager_cls

        platform_manager = manager_cls(mode="live-paper")
        platform_manager.register_platform("kucoin")
        platform_manager.start_platform_stream(
            "kucoin",
            symbols,
            market_type=market_type,
        )
        if logger is not None:
            logger.info(
                "BotCore: auto-started kucoin platform stream symbols=%s market_type=%s",
                symbols,
                market_type or "<auto>",
            )
        return platform_manager
    except Exception as exc:
        if logger is not None:
            logger.warning(
                "BotCore: platform stream auto-start failed: %s",
                exc,
            )
        return None


def _stop_runtime_platform_stream(platform_manager, logger=None):
    if platform_manager is None:
        return
    stop_stream = getattr(platform_manager, "stop_platform_stream", None)
    if not callable(stop_stream):
        return
    try:
        stop_stream("kucoin")
        if logger is not None:
            logger.info("BotCore: stopped kucoin platform stream")
    except Exception as exc:
        if logger is not None:
            logger.warning("BotCore: platform stream stop failed: %s", exc)


def apply_paper_gate_entry_guard(allow_flag, allocation, gate_active):
    if gate_active and allocation and allocation > 0:
        return False
    return allow_flag


def append_decision_log_csv_row(file_handle, timestamp_iso, decision, details=None):
    """Write a single decision log row with CSV-safe escaping."""
    writer = csv.writer(file_handle, lineterminator="\n")
    if details is None:
        writer.writerow([str(timestamp_iso), str(decision)])
    else:
        writer.writerow([str(timestamp_iso), str(decision), str(details)])


def _paper_trend_mixed_edge_over_fee_gate(
    *,
    simulate,
    symbol,
    strategy_name,
    regime_name,
    entry_decision,
    expected_edge_raw,
    estimated_round_trip_fee,
    expected_edge_net,
    edge_safety_margin,
):
    def _to_finite_float(value):
        try:
            value = float(value)
        except Exception:
            return None
        if not math.isfinite(value):
            return None
        return float(value)

    symbol_norm = str(symbol or "").strip().upper()
    strategy_norm = str(strategy_name or "").strip().lower()
    regime_norm = str(regime_name or "").strip().lower()
    side_norm = str(entry_decision or "").strip().lower()
    is_kucoin_futures_symbol = bool(
        symbol_norm.endswith("USDTM") or symbol_norm.endswith("USDCM")
    )
    candidate = bool(
        bool(simulate)
        and is_kucoin_futures_symbol
        and strategy_norm == "trendfollowing"
        and regime_norm == "mixed"
        and side_norm in ("buy", "sell")
    )

    expected_edge_raw_val = _to_finite_float(expected_edge_raw)
    estimated_round_trip_fee_val = _to_finite_float(estimated_round_trip_fee)
    expected_edge_net_val = _to_finite_float(expected_edge_net)
    edge_safety_margin_val = _to_finite_float(edge_safety_margin)
    if edge_safety_margin_val is None:
        edge_safety_margin_val = 0.0
    edge_safety_margin_val = max(0.0, float(edge_safety_margin_val))

    blocked = False
    allowed = False
    block_reason = None
    if candidate:
        if expected_edge_raw_val is None:
            blocked = True
            block_reason = "missing_expected_edge_raw"
        elif estimated_round_trip_fee_val is None:
            blocked = True
            block_reason = "missing_estimated_round_trip_fee"
        elif expected_edge_net_val is None:
            blocked = True
            block_reason = "missing_expected_edge_net"
        elif float(expected_edge_net_val) <= float(edge_safety_margin_val):
            blocked = True
            block_reason = "expected_edge_net_below_or_equal_margin"
        else:
            allowed = True

    return {
        "trend_mixed_edge_over_fee_candidate": bool(candidate),
        "trend_mixed_edge_over_fee_blocked": bool(blocked),
        "trend_mixed_edge_over_fee_allowed": bool(allowed),
        "trend_mixed_expected_edge_raw": expected_edge_raw_val,
        "trend_mixed_estimated_round_trip_fee": estimated_round_trip_fee_val,
        "trend_mixed_expected_edge_net": expected_edge_net_val,
        "trend_mixed_edge_safety_margin": float(edge_safety_margin_val),
        "trend_mixed_block_reason": str(block_reason) if block_reason else None,
    }


