def _env_flag(name, default="0"):
    import os

    return os.environ.get(name, default) == "1"


def _normalize_exit_reason_value(value):
    try:
        normalized = str(value).strip()
    except Exception:
        return None
    if normalized in ("", "null", "None", "none"):
        return None
    return normalized


def _classify_exit_owner(exit_reason, source_branch=None):
    reason_norm = str(exit_reason or "").strip().lower()
    source_norm = str(source_branch or "").strip().lower()

    if reason_norm in {"sl", "tp", "tp_usdt", "sl_usdt"}:
        return "risk_guard_exit"
    if reason_norm in {
        "auto_close_time_economics",
        "auto_close_time_fee_floor",
    }:
        return "economic_exit"
    if reason_norm in {
        "post_green_protective_exit",
        "post_green_rescue_refine_hold",
    }:
        return "post_green_protection_exit"
    if reason_norm in {
        "auto_close_weak_peak_decay",
        "weak_peak_stale_decay",
        "weak_peak_stale_decay_hard_window",
        "weak_peak_stale_decay_hard_window_feefloor_override",
    }:
        return "peak_decay_exit"
    if reason_norm in {
        "auto_close_hard",
        "auto_close_hard_near_zero",
        "auto_close_profit",
        "auto_close_loss_cap",
    }:
        return "time_based_exit"
    if reason_norm in {"opposite_signal"}:
        return "signal_reversal_exit"
    if reason_norm in {"manual_close_request", "position_close_request", "close_request"}:
        return "manual_close_request"
    if reason_norm in {
        "paper_run_end_force_close",
        "paper_run_once",
        "paper_run_once_force_close",
        "paper_run_cycles",
    }:
        return "run_end_cleanup_exit"

    if source_norm == "position_close_request":
        return "manual_close_request"
    if source_norm in {"paper_run_end_force_close", "exchange_sync"}:
        return "run_end_cleanup_exit"
    if source_norm in {"branch_auto_close", "mark_to_market_loop"}:
        return "time_based_exit"

    return "unclassified_exit_owner"


def _deterministic_close_reason_fallback(source_branch=None):
    source_norm = str(source_branch or "").strip().lower()
    if source_norm in {"position_close_request", "manual_close_request", "close_request"}:
        return {
            "exit_reason": "manual_close_request",
            "reason_source": "deterministic_fallback_manual_close_request",
        }
    return {
        "exit_reason": "close_reason_unclassified",
        "reason_source": "deterministic_fallback_unclassified",
    }


def _resolve_close_reason_with_owner(
    *,
    payload_exit_reason=None,
    close_execute_reason=None,
    execute_call_reason=None,
    candidate_reason=None,
    weak_peak_reason=None,
    source_branch=None,
):
    ordered_candidates = [
        ("position_payload_exit_reason", payload_exit_reason),
        ("close_execute_exit.reason", close_execute_reason),
        ("_execute_close_order.reason", execute_call_reason),
        ("close_candidate_normal.exit_reason_candidate", candidate_reason),
        ("weak_peak_decay_reason", weak_peak_reason),
    ]

    final_exit_reason = None
    reason_source = None
    for source_name, source_value in ordered_candidates:
        normalized = _normalize_exit_reason_value(source_value)
        if normalized is not None:
            final_exit_reason = normalized
            reason_source = source_name
            break

    if final_exit_reason is None:
        fallback = _deterministic_close_reason_fallback(source_branch=source_branch)
        final_exit_reason = fallback.get("exit_reason")
        reason_source = fallback.get("reason_source")

    return {
        "exit_reason": final_exit_reason,
        "reason_source": reason_source,
        "exit_owner": _classify_exit_owner(
            final_exit_reason,
            source_branch=source_branch,
        ),
    }


def _compute_lifecycle_ownership_flags(exit_reason, exit_owner):
    exit_reason_deterministic = bool(
        str(exit_reason or "") != "close_reason_unclassified"
    )
    exit_owner_deterministic = bool(
        str(exit_owner or "") != "unclassified_exit_owner"
    )
    reason_codes = []
    if not exit_reason_deterministic:
        reason_codes.append("close_reason_unclassified")
    if not exit_owner_deterministic:
        reason_codes.append("unclassified_exit_owner")
    lifecycle_ownership_deterministic = bool(
        exit_reason_deterministic and exit_owner_deterministic
    )
    return {
        "exit_reason_deterministic": bool(exit_reason_deterministic),
        "exit_owner_deterministic": bool(exit_owner_deterministic),
        "lifecycle_ownership_reason_codes": list(reason_codes),
        "lifecycle_ownership_deterministic": bool(
            lifecycle_ownership_deterministic
        ),
        "lifecycle_ownership_state": (
            "deterministic"
            if lifecycle_ownership_deterministic
            else "requires_review"
        ),
    }


def _finalize_close_lifecycle_state(
    close_lifecycle_state,
    close_lifecycle_terminal_state,
    symbol_name,
    pos_obj,
    *,
    success,
    block_code=None,
):
    trade_id_val = None
    if isinstance(pos_obj, dict):
        trade_id_val = pos_obj.get("trade_id")
    if trade_id_val:
        key = f"trade:{trade_id_val}"
    else:
        symbol_norm = str(symbol_name or "").strip().upper()
        key = f"symbol:{symbol_norm}" if symbol_norm else None
    if key is None:
        return None
    state = close_lifecycle_state.get(key)
    if state is None:
        return None
    finalized_at = float(time.time())
    terminal_snapshot = dict(state)
    terminal_snapshot["close_finalized"] = bool(success)
    terminal_snapshot["close_finalized_at"] = finalized_at
    terminal_snapshot["close_finalization_status"] = (
        "success" if success else "failed"
    )
    terminal_snapshot["close_finalization_block_code"] = block_code
    terminal_snapshot["close_in_flight"] = False
    if success:
        close_lifecycle_state.pop(key, None)
    else:
        state["close_in_flight"] = False
        state["close_requested_at"] = None
        state["close_last_attempt_ts"] = finalized_at
        state["last_block_code"] = block_code
    if isinstance(close_lifecycle_terminal_state, dict):
        close_lifecycle_terminal_state[key] = terminal_snapshot
    return terminal_snapshot


def _select_layered_exit_candidate(
    allowed_candidates,
    *,
    hard_reason_names=None,
    prefer_non_hard=True,
):
    candidates = [c for c in (allowed_candidates or []) if isinstance(c, dict)]
    if not candidates:
        return None, False

    hard_reasons = {
        str(reason or "") for reason in (hard_reason_names or []) if reason is not None
    }
    hard_candidates = [
        c for c in candidates if str(c.get("reason") or "") in hard_reasons
    ]
    non_hard_candidates = [
        c for c in candidates if str(c.get("reason") or "") not in hard_reasons
    ]

    def _selection_key(candidate):
        expected_net = candidate.get("expected_net_after_fee")
        try:
            expected_net_value = float(expected_net)
        except Exception:
            expected_net_value = float("-inf")
        try:
            priority_value = int(candidate.get("priority") or 0)
        except Exception:
            priority_value = 0
        return (expected_net_value, priority_value)

    use_non_hard_pool = bool(prefer_non_hard and non_hard_candidates)
    force_hard_pool = False
    if use_non_hard_pool and hard_candidates:
        best_non_hard = max(non_hard_candidates, key=_selection_key)
        try:
            best_non_hard_net = float(best_non_hard.get("expected_net_after_fee"))
        except Exception:
            best_non_hard_net = float("-inf")
        if best_non_hard_net < 0.0:
            use_non_hard_pool = False
            force_hard_pool = True

    if use_non_hard_pool:
        selection_pool = non_hard_candidates
    elif force_hard_pool and hard_candidates:
        selection_pool = hard_candidates
    else:
        selection_pool = candidates

    return max(selection_pool, key=_selection_key), bool(non_hard_candidates)


def _should_post_green_hold_guard_bypass(
    *,
    exit_reason,
    post_green_metrics,
    current_net_after_fee,
    post_green_trigger_seen=False,
):
    if str(exit_reason or "") != "post_green_protective_exit":
        return False
    if bool(post_green_trigger_seen):
        return True
    if not isinstance(post_green_metrics, dict):
        return False

    try:
        giveback_ratio = float(post_green_metrics.get("post_green_giveback_ratio"))
    except Exception:
        giveback_ratio = None
    try:
        net_after_fee = float(current_net_after_fee)
    except Exception:
        net_after_fee = None

    hard_window_bypass = bool(post_green_metrics.get("post_green_hard_close_imminent"))
    severe_giveback_negative_residual_bypass = bool(
        giveback_ratio is not None
        and giveback_ratio >= 1.0
        and net_after_fee is not None
        and net_after_fee <= 0.0
    )
    return bool(hard_window_bypass or severe_giveback_negative_residual_bypass)


def _should_fail_closed_post_green_red_close(
    *,
    exit_reason,
    selected_expected_net_after_fee,
    post_green_peak_mfe,
    pre_hard_close_best_feasible_net,
):
    reason_norm = str(exit_reason or "").strip().lower()
    if reason_norm not in {
        "post_green_protective_exit",
        "auto_close_weak_peak_decay",
        "weak_peak_stale_decay",
        "weak_peak_stale_decay_hard_window",
        "weak_peak_stale_decay_hard_window_feefloor_override",
    }:
        return False
    try:
        selected_net = float(selected_expected_net_after_fee)
    except Exception:
        selected_net = None
    try:
        peak_mfe = float(post_green_peak_mfe)
    except Exception:
        peak_mfe = None
    try:
        feasible_net = float(pre_hard_close_best_feasible_net)
    except Exception:
        feasible_net = None
    if (
        peak_mfe is not None
        and peak_mfe > 0.0
        and selected_net is not None
        and selected_net <= 0.0
        and feasible_net is not None
        and feasible_net > 0.0
    ):
        min_green_capture_fraction = 0.20
        min_required_feasible_net = peak_mfe * min_green_capture_fraction
        return feasible_net >= min_required_feasible_net
    return False


def _resolve_entry_candidate_strategy(candidate_payload):
    if not isinstance(candidate_payload, dict):
        return ""
    strategy_candidates = []
    for key in ("strategy", "main_strategy", "selected_strategy"):
        if key in candidate_payload:
            strategy_candidates.append(candidate_payload.get(key))
    signal_payload = candidate_payload.get("signal")
    if isinstance(signal_payload, dict):
        for key in ("strategy", "main_strategy", "selected_strategy"):
            if key in signal_payload:
                strategy_candidates.append(signal_payload.get(key))
    for value in strategy_candidates:
        try:
            strategy_text = str(value or "").strip()
        except Exception:
            strategy_text = ""
        if strategy_text and strategy_text.lower() not in {"none", "null"}:
            return strategy_text
    return ""


def should_bypass_symbol_strategy_guard_for_hold(side, entry_ignore_hold_signals):
    try:
        side_name = str(side or "").strip().lower()
    except Exception:
        side_name = ""
    return bool(entry_ignore_hold_signals and side_name == "hold")


def should_apply_universal_hold_passthrough(
    *,
    strategy_name,
    explicit_hold_side,
    universal_hold_passthrough_enabled,
    live_mode,
):
    try:
        strategy_norm = str(strategy_name or "").strip().lower()
    except Exception:
        strategy_norm = ""
    return bool(
        bool(universal_hold_passthrough_enabled)
        and not bool(live_mode)
        and bool(explicit_hold_side)
        and strategy_norm == "universal"
    )


def _resolve_side_guard_history_inputs(pnl_hist, history_source, require_runtime_only):
    safe_pnl_hist = []
    for value in pnl_hist or []:
        try:
            safe_pnl_hist.append(float(value))
        except Exception:
            continue
    source_hist = list(history_source or [])
    if len(source_hist) < len(safe_pnl_hist):
        source_hist.extend(["unknown"] * (len(safe_pnl_hist) - len(source_hist)))
    elif len(source_hist) > len(safe_pnl_hist):
        source_hist = source_hist[-len(safe_pnl_hist):]

    bootstrap_trade_count = sum(
        1 for src in source_hist if str(src or "").strip().lower() == "bootstrap"
    )
    runtime_trade_count = sum(
        1 for src in source_hist if str(src or "").strip().lower() == "runtime"
    )
    if require_runtime_only:
        effective_pnl_hist = [
            pnl
            for pnl, src in zip(safe_pnl_hist, source_hist)
            if str(src or "").strip().lower() == "runtime"
        ]
        history_source = "runtime_only"
    else:
        effective_pnl_hist = list(safe_pnl_hist)
        history_source = "all_history"

    return {
        "effective_pnl_hist": effective_pnl_hist,
        "history_source": history_source,
        "bootstrap_trade_count": int(bootstrap_trade_count),
        "runtime_trade_count": int(runtime_trade_count),
        "effective_trade_count": int(len(effective_pnl_hist)),
        "bootstrap_ignored": bool(require_runtime_only and bootstrap_trade_count > 0),
    }


def _build_post_green_hold_guard_bypass_telemetry(
    *,
    symbol,
    trade_id,
    reason,
    source_branch,
    exit_min_hold_sec,
    post_green_candidate_seen,
    post_green_trigger_seen,
    post_green_metrics=None,
):
    bypass_reason = "post_green_hold_guard_bypass"
    if bool(post_green_trigger_seen):
        bypass_reason = "armed_post_green_trigger_seen"
    elif isinstance(post_green_metrics, dict):
        if bool(post_green_metrics.get("post_green_hard_close_imminent")):
            bypass_reason = "post_green_hard_close_imminent"
        else:
            try:
                giveback_ratio = float(
                    post_green_metrics.get("post_green_giveback_ratio")
                )
            except Exception:
                giveback_ratio = None
            if giveback_ratio is not None and giveback_ratio >= 1.0:
                bypass_reason = "post_green_severe_giveback_negative_residual"

    payload = {
        "event": "close_execute_post_green_hold_guard_bypass",
        "symbol": symbol,
        "trade_id": trade_id,
        "reason": reason,
        "source_branch": source_branch,
        "exit_min_hold_sec": exit_min_hold_sec,
        "post_green_hold_guard_bypass": True,
        "post_green_hold_guard_bypass_reason": bypass_reason,
        "post_green_lifecycle_candidate_seen": bool(post_green_candidate_seen),
        "post_green_lifecycle_trigger_seen": bool(post_green_trigger_seen),
    }
    if isinstance(post_green_metrics, dict):
        payload["post_green_hard_close_imminent"] = bool(
            post_green_metrics.get("post_green_hard_close_imminent")
        )
        payload["post_green_giveback_ratio"] = post_green_metrics.get(
            "post_green_giveback_ratio"
        )
        payload["post_green_trigger_mode"] = post_green_metrics.get(
            "post_green_trigger_mode"
        )
        payload["post_green_attempt_seq"] = post_green_metrics.get(
            "post_green_attempt_seq"
        )
        payload["post_green_branch_seq"] = post_green_metrics.get(
            "post_green_branch_seq"
        )
        payload["post_green_peak_to_burden_ratio"] = post_green_metrics.get(
            "post_green_peak_to_burden_ratio"
        )
        payload["post_green_bnr_time_forced_exit_sec"] = post_green_metrics.get(
            "post_green_bnr_time_forced_exit_sec"
        )
        payload["post_green_trigger_reason_detail"] = post_green_metrics.get(
            "post_green_trigger_reason_detail"
        )
        payload["post_green_rescue_exit_reason"] = post_green_metrics.get(
            "post_green_rescue_exit_reason"
        )
    return payload


