def _resolve_entry_min_net_threshold(
    entry_min_net_usdt,
    *,
    alpha_micro_exploration_state=None,
    alpha_micro_exploration_net_target_scale=0.5,
    alpha_universe_exploration_active=False,
    alpha_universe_exploration_net_target_scale=0.35,
):
    base_entry_min_net_usdt = float(entry_min_net_usdt)
    effective_entry_min_net_usdt = float(base_entry_min_net_usdt)
    dynamic_adjustment_applied = False
    if (
        effective_entry_min_net_usdt > 0
        and isinstance(alpha_micro_exploration_state, dict)
        and alpha_micro_exploration_state.get("only_micro_signals")
    ):
        try:
            net_scale = min(
                1.0,
                max(0.0, float(alpha_micro_exploration_net_target_scale)),
            )
        except Exception:
            net_scale = 0.5
        effective_entry_min_net_usdt = (
            float(effective_entry_min_net_usdt) * float(net_scale)
        )
        alpha_micro_exploration_state["net_target_scale_applied"] = float(net_scale)
        dynamic_adjustment_applied = True
    if effective_entry_min_net_usdt > 0 and alpha_universe_exploration_active:
        try:
            net_scale = min(
                1.0,
                max(0.0, float(alpha_universe_exploration_net_target_scale)),
            )
        except Exception:
            net_scale = 0.35
        effective_entry_min_net_usdt = (
            float(effective_entry_min_net_usdt) * float(net_scale)
        )
        dynamic_adjustment_applied = True
    return {
        "base_entry_min_net_usdt": float(base_entry_min_net_usdt),
        "effective_entry_min_net_usdt": float(effective_entry_min_net_usdt),
        "dynamic_adjustment_applied": bool(dynamic_adjustment_applied),
    }


def _paper_post_green_protective_exit_decision(
    *,
    simulate,
    symbol,
    position,
    current_net_after_fee,
    pos_age_sec,
    paper_auto_close_sec,
    paper_auto_close_hard_sec=None,
    now_dt=None,
):
    soft_residual_floor_abs = 0.003
    positive_residual_giveback_trigger = float(
        os.environ.get("PAPER_POST_GREEN_GIVEBACK_TRIGGER", "0.15")
    )
    positive_residual_giveback_trigger = min(
        positive_residual_giveback_trigger,
        0.12,
    )
    positive_residual_hard_window_giveback_trigger = 0.05
    negative_residual_hard_window_floor_abs = 0.020
    hard_window_quality_filter_giveback_floor = 0.85
    rescue_refine_ratio_floor = 1.0
    rescue_refine_max_time_since_peak_sec = 45.0
    rescue_refine_max_giveback_ratio = 2.0
    soft_residual_quality_max_time_since_peak_sec = 9.0
    soft_residual_quality_max_giveback_ratio = 1.35
    micro_mfe_exit_threshold = 0.0008
    micro_mfe_exit_min_time_since_peak_sec = 4.0
    micro_mfe_peak_to_burden_ratio_ceiling = 0.20
    bnr_time_forced_exit_sec = 1.0
    bnr_loss_cap_abs = 0.0022
    bnr_loss_cap_min_peak_to_burden_ratio = 0.40
    metrics = {
        "post_green_attempt_seq": None,
        "post_green_branch_seq": None,
        "post_green_peak_mfe": None,
        "post_green_time_since_peak_sec": None,
        "post_green_giveback_ratio": None,
        "post_green_peak_to_current_delta": None,
        "post_green_peak_capture_ratio": None,
        "post_green_peak_to_burden_ratio": None,
        "post_green_time_until_hard_close_sec": None,
        "post_green_hard_close_window_sec": None,
        "post_green_hard_close_imminent": False,
        "post_green_exit_reason": "post_green_protective_exit",
        "post_green_trigger_mode": None,
        "post_green_trigger_reason_detail": None,
        "post_green_trigger_giveback_threshold": None,
        "post_green_trigger_time_since_peak_sec": None,
        "post_green_trigger_giveback_ratio": None,
        "post_green_trigger_residual_edge": None,
        "post_green_bnr_time_forced_exit_sec": bnr_time_forced_exit_sec,
        "post_green_bnr_loss_cap_abs": bnr_loss_cap_abs,
        "post_green_trigger_blocked_negative_residual": False,
        "post_green_trigger_residual_floor_mode": "absolute_negative_epsilon",
        "post_green_trigger_residual_floor_value": soft_residual_floor_abs,
        "post_green_trigger_soft_floor_passed": False,
        "post_green_trigger_soft_floor_blocked": False,
        "post_green_trigger_hard_window_soft_floor_override": False,
        "post_green_trigger_hard_window_soft_floor_value": negative_residual_hard_window_floor_abs,
        "post_green_quality_filter_candidate": False,
        "post_green_quality_filter_passed": False,
        "post_green_quality_filter_blocked": False,
        "post_green_quality_filter_reason": None,
        "post_green_quality_filter_hard_window_override": False,
        "post_green_quality_filter_hard_window_override_giveback_floor": hard_window_quality_filter_giveback_floor,
        "post_green_quality_filter_peak_mfe": None,
        "post_green_quality_filter_residual_edge": None,
        "post_green_quality_filter_giveback_ratio": None,
        "post_green_quality_filter_time_since_peak_sec": None,
        "post_green_rescue_refine_candidate": False,
        "post_green_rescue_refine_triggered": False,
        "post_green_rescue_refine_skipped": False,
        "post_green_rescue_ratio_band": None,
        "post_green_rescue_burden_equivalent": None,
        "post_green_rescue_peak_mfe": None,
        "post_green_rescue_time_since_peak_sec": None,
        "post_green_rescue_giveback_ratio": None,
        "post_green_rescue_exit_reason": None,
        "post_green_skip_reason": None,
        "post_green_trigger_positive_residual_required": False,
        "post_green_trigger_before_zero_cross": False,
        "post_green_trigger_residual_sign": None,
        # PAPER exit-quality classification (set at trigger point):
        # micro_mfe_under_fee_burden | late_post_green_exit | standard_protective_exit
        "post_green_exit_quality_class": "standard_protective_exit",
    }
    post_green_contract_eligible = False

    def _finalize_contract(branch_seq=None):
        return _build_post_green_contract_telemetry_fields(
            metrics=metrics,
            position=position,
            branch_seq=branch_seq,
        )

    def _skip(reason, branch_seq=None):
        metrics["post_green_skip_reason"] = str(reason or "unknown")
        if post_green_contract_eligible:
            _finalize_contract(branch_seq=f"skip:{reason or 'unknown'}" if branch_seq is None else branch_seq)
        return False, str(reason or "unknown"), metrics

    if not simulate:
        return _skip("not_paper_simulation")
    if not isinstance(position, dict):
        return _skip("position_unavailable")
    symbol_name = str(symbol or position.get("symbol") or "").strip().upper()
    open_snapshot = (
        position.get("open_snapshot")
        if isinstance(position.get("open_snapshot"), dict)
        else {}
    )
    if not (
        symbol_name.endswith("USDTM")
        and str(open_snapshot.get("source") or "") == "kucoin_futures_ticker"
    ):
        return _skip("not_kucoin_paper_symbol")
    try:
        pos_age_val = float(pos_age_sec)
    except Exception:
        pos_age_val = None
    if pos_age_val is None:
        return _skip("position_age_unavailable")
    try:
        time_gate = max(1.0, float(paper_auto_close_sec))
    except Exception:
        time_gate = 1.0
    if pos_age_val < time_gate:
        return _skip("soft_timer_not_reached")
    try:
        current_net_val = float(current_net_after_fee)
    except Exception:
        return _skip("current_net_unavailable")
    if current_net_val <= 0:
        metrics["post_green_trigger_positive_residual_required"] = True
        metrics["post_green_trigger_before_zero_cross"] = True
        metrics["post_green_trigger_residual_sign"] = "negative_or_zero"
    else:
        metrics["post_green_trigger_residual_sign"] = "positive"
    post_green_contract_eligible = True
    peak_mfe = position.get("mfe")
    if peak_mfe is None:
        peak_mfe = position.get("max_unrealized_pnl")
    try:
        peak_mfe = float(peak_mfe)
    except Exception:
        peak_mfe = None
    metrics["post_green_peak_mfe"] = peak_mfe
    metrics["post_green_rescue_peak_mfe"] = peak_mfe
    if peak_mfe is None or peak_mfe <= 0.0:
        return _skip("never_green")
    post_green_contract_eligible = True
    peak_ts_raw = (
        position.get("peak_mfe_ts")
        or position.get("max_unrealized_pnl_ts")
        or position.get("first_positive_mfe_ts")
    )
    if peak_ts_raw in (None, ""):
        return _skip("peak_timestamp_unavailable")
    try:
        peak_dt = datetime.fromisoformat(str(peak_ts_raw).replace("Z", "+00:00"))
    except Exception:
        return _skip("peak_timestamp_unavailable")
    if peak_dt.tzinfo is None:
        peak_dt = peak_dt.replace(tzinfo=timezone.utc)
    if now_dt is None:
        now_dt = datetime.now(timezone.utc)
    if now_dt.tzinfo is None:
        now_dt = now_dt.replace(tzinfo=timezone.utc)
    time_since_peak_sec = max(0.0, (now_dt - peak_dt).total_seconds())
    metrics["post_green_time_since_peak_sec"] = time_since_peak_sec
    metrics["post_green_rescue_time_since_peak_sec"] = time_since_peak_sec
    giveback_ratio = (float(peak_mfe) - float(current_net_val)) / float(peak_mfe)
    metrics["post_green_giveback_ratio"] = giveback_ratio
    metrics["post_green_rescue_giveback_ratio"] = giveback_ratio
    metrics["post_green_peak_to_current_delta"] = float(peak_mfe) - float(current_net_val)
    metrics["post_green_peak_capture_ratio"] = float(current_net_val) / float(peak_mfe)
    metrics["post_green_trigger_time_since_peak_sec"] = time_since_peak_sec
    metrics["post_green_trigger_giveback_ratio"] = giveback_ratio
    metrics["post_green_trigger_residual_edge"] = current_net_val
    metrics["post_green_quality_filter_peak_mfe"] = peak_mfe
    metrics["post_green_quality_filter_residual_edge"] = current_net_val
    metrics["post_green_quality_filter_giveback_ratio"] = giveback_ratio
    metrics["post_green_quality_filter_time_since_peak_sec"] = time_since_peak_sec
    hard_close_window_sec = None
    time_until_hard_close_sec = None
    hard_close_imminent = False
    try:
        hard_close_gate = float(paper_auto_close_hard_sec)
    except Exception:
        hard_close_gate = None
    if hard_close_gate is not None and hard_close_gate > 0.0:
        hard_close_window_sec = min(45.0, max(20.0, float(time_gate) * 2.0))
        time_until_hard_close_sec = max(0.0, float(hard_close_gate) - float(pos_age_val))
        hard_close_imminent = float(pos_age_val) >= max(
            float(time_gate),
            float(hard_close_gate) - float(hard_close_window_sec),
        )
    metrics["post_green_time_until_hard_close_sec"] = time_until_hard_close_sec
    metrics["post_green_hard_close_window_sec"] = hard_close_window_sec
    metrics["post_green_hard_close_imminent"] = bool(hard_close_imminent)

    def _post_green_float(val):
        try:
            if val is None:
                return None
            out = float(val)
        except Exception:
            return None
        if out != out or out in (float("inf"), float("-inf")):
            return None
        return out

    execution_cost_floor_abs = None
    try:
        qty_abs = abs(_post_green_float(position.get("amount")) or 0.0)
        fee_open = _post_green_float(position.get("fee_cost_open")) or 0.0
        fee_close = _post_green_float(position.get("fee_cost_close"))
        close_px_for_fee = _post_green_float(position.get("mark_price"))
        if close_px_for_fee is None:
            close_px_for_fee = (
                _post_green_float(position.get("entry_price"))
                or _post_green_float(position.get("price"))
            )
        fee_rate_close = _post_green_float(position.get("fee_rate_close"))
        if fee_rate_close is None:
            fee_rate_close = _post_green_float(position.get("fee_rate_open"))
        if fee_open > 0.0 or fee_close is not None:
            execution_cost_floor_abs = max(
                0.0,
                float(fee_open) + float(fee_close or 0.0),
            )
        elif fee_open > 0.0:
            execution_cost_floor_abs = float(fee_open)
        if (
            fee_close is None
            and qty_abs > 0.0
            and close_px_for_fee is not None
            and fee_rate_close is not None
            and fee_rate_close > 0.0
        ):
            fee_close_est = abs(float(close_px_for_fee) * float(qty_abs)) * float(
                fee_rate_close
            )
            execution_cost_floor_abs = max(
                0.0,
                float(fee_open) + float(fee_close_est),
            )
    except Exception:
        execution_cost_floor_abs = None
    burden_floor_abs = float(soft_residual_floor_abs)
    if execution_cost_floor_abs is not None and execution_cost_floor_abs > 0.0:
        burden_floor_abs = min(
            burden_floor_abs,
            float(execution_cost_floor_abs),
        )
    burden_equivalent = max(
        abs(float(burden_floor_abs)),
        abs(float(current_net_val)),
    )
    metrics["post_green_rescue_burden_equivalent"] = burden_equivalent
    effective_soft_residual_floor_abs = float(burden_floor_abs)
    if (
        peak_mfe is not None
        and peak_mfe > 0.0
        and float(peak_mfe) <= float(soft_residual_floor_abs) + 0.001
    ):
        effective_soft_residual_floor_abs = max(
            effective_soft_residual_floor_abs,
            float(peak_mfe),
        )
    peak_to_burden_ratio = None
    if burden_equivalent > 0.0:
        peak_to_burden_ratio = float(peak_mfe) / float(burden_equivalent)
    metrics["post_green_peak_to_burden_ratio"] = peak_to_burden_ratio
    if peak_to_burden_ratio is None:
        rescue_ratio_band = "unknown"
    elif peak_to_burden_ratio < 0.5:
        rescue_ratio_band = "lt_0.5"
    elif peak_to_burden_ratio < 1.0:
        rescue_ratio_band = "0.5_to_lt_1.0"
    else:
        rescue_ratio_band = "ge_1.0"
    metrics["post_green_rescue_ratio_band"] = rescue_ratio_band
    peak_hold_floor_sec = max(4.0, min(8.0, float(time_gate) * 0.4))
    # BNR is reserved for the genuinely late, deeply-given-back tail so it
    # does not steal micro-MFE or soft-residual paths on unstable early peaks.
    bnr_time_forced_exit_giveback_floor = 5.51
    bnr_time_forced_exit_ready = bool(
        peak_mfe is not None
        and float(peak_mfe) >= float(micro_mfe_exit_threshold)
        and current_net_val <= 0.0
        and time_since_peak_sec >= float(bnr_time_forced_exit_sec)
        and (peak_to_burden_ratio is None or peak_to_burden_ratio < 1.0)
        and giveback_ratio >= float(bnr_time_forced_exit_giveback_floor)
    )
    bnr_loss_cap_exit_ready = bool(
        not bnr_time_forced_exit_ready
        and peak_mfe is not None
        and float(peak_mfe) >= float(micro_mfe_exit_threshold)
        and current_net_val <= -float(bnr_loss_cap_abs)
        and time_since_peak_sec >= float(bnr_time_forced_exit_sec)
        and time_since_peak_sec <= 45.0
        and peak_to_burden_ratio is not None
        and peak_to_burden_ratio >= float(bnr_loss_cap_min_peak_to_burden_ratio)
        and peak_to_burden_ratio < 1.0
    )
    if bnr_time_forced_exit_ready or bnr_loss_cap_exit_ready:
        metrics["post_green_bnr_time_forced_exit"] = True
        metrics["post_green_trigger_mode"] = "bnr_time_forced_exit"
        metrics["post_green_exit_reason"] = "post_green_protective_exit"
        metrics["post_green_trigger_reason_detail"] = (
            "bnr_time_forced_exit"
            if bnr_time_forced_exit_ready
            else "bnr_loss_cap_exit"
        )
        metrics["post_green_rescue_exit_reason"] = "post_green_protective_exit"
        # Late decay: peak never cleared fee burden — classify explicitly.
        metrics["post_green_exit_quality_class"] = "late_post_green_exit"
        _finalize_contract(branch_seq="bnr_time_forced_exit")
        return True, "bnr_time_forced_exit", metrics
    if time_since_peak_sec <= peak_hold_floor_sec:
        return _skip("peak_too_recent")
    if giveback_ratio <= 0.0:
        return _skip("at_or_above_peak")
    giveback_trigger_threshold = 0.25
    if current_net_val > 0.0:
        giveback_trigger_threshold = float(positive_residual_giveback_trigger)
        if hard_close_imminent:
            giveback_trigger_threshold = min(
                giveback_trigger_threshold,
                float(positive_residual_hard_window_giveback_trigger),
            )
    metrics["post_green_trigger_giveback_threshold"] = giveback_trigger_threshold
    if giveback_ratio < giveback_trigger_threshold:
        return _skip("giveback_below_trigger")
    metrics["post_green_trigger_residual_floor_mode"] = (
        "confirmed_peak_dynamic_epsilon"
        if effective_soft_residual_floor_abs > float(soft_residual_floor_abs)
        else "execution_cost_negative_epsilon"
        if execution_cost_floor_abs is not None
        and execution_cost_floor_abs > 0.0
        and effective_soft_residual_floor_abs < float(soft_residual_floor_abs)
        else "absolute_negative_epsilon"
    )
    metrics["post_green_trigger_residual_floor_value"] = (
        effective_soft_residual_floor_abs
    )
    soft_floor_passed = current_net_val > -float(effective_soft_residual_floor_abs)
    hard_window_soft_floor_override = bool(
        not soft_floor_passed
        and hard_close_imminent
        and current_net_val <= 0.0
        and peak_to_burden_ratio is not None
        and peak_to_burden_ratio >= float(rescue_refine_ratio_floor)
        and giveback_ratio >= float(hard_window_quality_filter_giveback_floor)
        and current_net_val > -float(negative_residual_hard_window_floor_abs)
    )
    if hard_window_soft_floor_override:
        soft_floor_passed = True
        metrics["post_green_trigger_hard_window_soft_floor_override"] = True
        metrics["post_green_trigger_residual_floor_mode"] = (
            "hard_window_negative_epsilon"
        )
        metrics["post_green_trigger_residual_floor_value"] = (
            float(negative_residual_hard_window_floor_abs)
        )
    metrics["post_green_trigger_soft_floor_passed"] = bool(soft_floor_passed)
    metrics["post_green_trigger_soft_floor_blocked"] = not bool(soft_floor_passed)
    micro_mfe_quality_ceiling_passed = bool(
        giveback_ratio is not None
        and float(giveback_ratio) <= float(soft_residual_quality_max_giveback_ratio)
    )
    micro_mfe_economic_kill_ready = bool(
        peak_mfe is not None
        and float(peak_mfe) < float(micro_mfe_exit_threshold)
        and peak_to_burden_ratio is not None
        # Reserve the micro branch for genuinely tiny peaks only. Borderline
        # sub-burden peaks are left to the normal post-green path instead of
        # being force-owned by the micro exit branch.
        and float(peak_to_burden_ratio)
        <= float(micro_mfe_peak_to_burden_ratio_ceiling)
        and current_net_val <= 0.0
        and time_since_peak_sec >= float(micro_mfe_exit_min_time_since_peak_sec)
        # Note: quality ceiling intentionally not applied — tiny peaks under
        # fee burden have no recovery value regardless of giveback ratio.
    )
    if micro_mfe_economic_kill_ready:
        metrics["post_green_micro_mfe_forced_exit"] = True
        metrics["post_green_trigger_mode"] = "micro_mfe_forced_exit"
        metrics["post_green_exit_reason"] = "post_green_protective_exit"
        metrics["post_green_trigger_reason_detail"] = "micro_mfe_forced_exit"
        metrics["post_green_rescue_exit_reason"] = "post_green_protective_exit"
        # Tiny peak never outran fee burden — classify explicitly.
        metrics["post_green_exit_quality_class"] = "micro_mfe_under_fee_burden"
        _finalize_contract(branch_seq="micro_mfe_forced_exit")
        return True, "micro_mfe_forced_exit", metrics
    if not soft_floor_passed:
        metrics["post_green_trigger_blocked_negative_residual"] = True
        # Micro-MFE economic kill: if the observed tiny peak never outran
        # burden, is still within the soft-quality giveback ceiling, and has
        # stabilized long enough, exit now instead of waiting for a longer
        # hold path that has already shown no recovery value.
        if micro_mfe_economic_kill_ready:
            metrics["post_green_micro_mfe_forced_exit"] = True
            metrics["post_green_trigger_mode"] = "micro_mfe_forced_exit"
            metrics["post_green_exit_reason"] = "post_green_protective_exit"
            metrics["post_green_trigger_reason_detail"] = "micro_mfe_forced_exit"
            metrics["post_green_rescue_exit_reason"] = "post_green_protective_exit"
            # Tiny peak never outran fee burden — classify explicitly.
            metrics["post_green_exit_quality_class"] = "micro_mfe_under_fee_burden"
            _finalize_contract(branch_seq="micro_mfe_forced_exit")
            return True, "micro_mfe_forced_exit", metrics
        # BNR time-based forced exit: positions where loss already exceeds peak
        # profit (peak_to_burden_ratio < 1.0) have no recovery hope — exit early
        # to cap the loss instead of waiting for the 90 s hard-window override.
        # Positions where MFE >= burden (ratio >= 1.0) are left for rescue_refine.
        if bnr_time_forced_exit_ready or bnr_loss_cap_exit_ready:
            metrics["post_green_bnr_time_forced_exit"] = True
            metrics["post_green_trigger_mode"] = "bnr_time_forced_exit"
            metrics["post_green_exit_reason"] = "post_green_protective_exit"
            metrics["post_green_trigger_reason_detail"] = (
                "bnr_time_forced_exit"
                if bnr_time_forced_exit_ready
                else "bnr_loss_cap_exit"
            )
            metrics["post_green_rescue_exit_reason"] = "post_green_protective_exit"
            # Late decay: peak never cleared fee burden — classify explicitly.
            metrics["post_green_exit_quality_class"] = "late_post_green_exit"
            _finalize_contract(branch_seq="bnr_time_forced_exit")
            return True, "bnr_time_forced_exit", metrics
        return _skip("blocked_negative_residual")
    rescue_refine_candidate = bool(
        symbol_name != "SOLUSDTM"
        and current_net_val <= 0.0
        and peak_to_burden_ratio is not None
        and peak_to_burden_ratio >= float(rescue_refine_ratio_floor)
    )
    metrics["post_green_rescue_refine_candidate"] = rescue_refine_candidate
    if rescue_refine_candidate:
        rescue_refine_should_hold = bool(
            time_since_peak_sec <= float(rescue_refine_max_time_since_peak_sec)
            and giveback_ratio <= float(rescue_refine_max_giveback_ratio)
        )
        if rescue_refine_should_hold:
            metrics["post_green_rescue_refine_triggered"] = True
            metrics["post_green_rescue_exit_reason"] = "post_green_rescue_refine_hold"
            return _skip("rescue_refine_hold")
        metrics["post_green_rescue_refine_skipped"] = True
        metrics["post_green_rescue_exit_reason"] = "post_green_protective_exit"
    quality_filter_candidate = bool(
        current_net_val <= 0.0 and symbol_name != "SOLUSDTM"
    )
    metrics["post_green_quality_filter_candidate"] = quality_filter_candidate
    if quality_filter_candidate:
        quality_filter_reasons = []
        quality_filter_weak_peak = bool(
            peak_to_burden_ratio is not None and peak_to_burden_ratio < 0.5
        )
        quality_filter_requires_strong_peak = bool(
            peak_to_burden_ratio is not None
            and peak_to_burden_ratio >= float(rescue_refine_ratio_floor)
        )
        quality_filter_is_late = (
            time_since_peak_sec > float(soft_residual_quality_max_time_since_peak_sec)
        )
        quality_filter_has_excessive_giveback = (
            giveback_ratio > float(soft_residual_quality_max_giveback_ratio)
        )
        if quality_filter_is_late:
            quality_filter_reasons.append("late_after_peak")
        if quality_filter_has_excessive_giveback:
            quality_filter_reasons.append("excessive_giveback")
        quality_filter_hard_window_override = bool(
            hard_close_imminent
            and current_net_val <= 0.0
            and giveback_ratio >= float(hard_window_quality_filter_giveback_floor)
        )
        metrics["post_green_quality_filter_hard_window_override"] = bool(
            quality_filter_hard_window_override
        )
        if quality_filter_hard_window_override and not quality_filter_requires_strong_peak:
            metrics["post_green_quality_filter_blocked"] = True
            metrics["post_green_quality_filter_reason"] = (
                "hard_window_override_blocked_weak_peak_to_burden"
            )
            return _skip("quality_filter_blocked")
        if (
            quality_filter_weak_peak
            and quality_filter_is_late
            and quality_filter_has_excessive_giveback
            and not quality_filter_hard_window_override
        ):
            metrics["post_green_quality_filter_blocked"] = True
            metrics["post_green_quality_filter_reason"] = (
                "late_after_peak_and_excessive_giveback_weak_peak_to_burden"
            )
            return _skip("quality_filter_blocked")
        if (
            quality_filter_requires_strong_peak
            and quality_filter_is_late
            and quality_filter_has_excessive_giveback
            and not quality_filter_hard_window_override
        ):
            metrics["post_green_quality_filter_blocked"] = True
            metrics["post_green_quality_filter_reason"] = "_and_".join(
                quality_filter_reasons
            )
            return _skip("quality_filter_blocked")
        if quality_filter_hard_window_override:
            metrics["post_green_quality_filter_reason"] = "hard_window_override"
        metrics["post_green_quality_filter_passed"] = True
    if current_net_val > 0.0:
        if hard_close_imminent:
            metrics["post_green_trigger_mode"] = "peak_giveback_positive_residual_hard_window"
            metrics["post_green_trigger_reason_detail"] = "positive_residual_hard_close_window"
        else:
            metrics["post_green_trigger_mode"] = "peak_giveback_positive_residual"
            metrics["post_green_trigger_reason_detail"] = "positive_residual_giveback"
    else:
        if hard_window_soft_floor_override:
            metrics["post_green_trigger_mode"] = (
                "peak_giveback_soft_residual_floor_hard_window_override"
            )
            metrics["post_green_trigger_reason_detail"] = (
                "soft_residual_floor_hard_window_override"
            )
        else:
            metrics["post_green_trigger_mode"] = "peak_giveback_soft_residual_floor"
            metrics["post_green_trigger_reason_detail"] = "soft_residual_floor"
        # PAPER exit-quality guard: negative-residual soft-floor triggers where
        # peak MFE never cleared fee burden are micro-MFE cases, not quality exits.
        if (
            peak_to_burden_ratio is not None
            and float(peak_to_burden_ratio) < 1.0
        ):
            metrics["post_green_exit_quality_class"] = "micro_mfe_under_fee_burden"
            metrics["post_green_trigger_reason_detail"] = "micro_mfe_under_fee_burden"
    if metrics["post_green_rescue_exit_reason"] is None:
        metrics["post_green_rescue_exit_reason"] = "post_green_protective_exit"
    metrics["post_green_skip_reason"] = None
    _finalize_contract()
    return True, "triggered", metrics


def _paper_post_green_protective_terminal_outcome_marker(
    *,
    candidate_seen,
    skipped_seen,
    triggered_seen,
    final_exit_reason=None,
    last_skip_reason=None,
    post_green_metrics=None,
):
    candidate_seen = bool(candidate_seen)
    skipped_seen = bool(skipped_seen)
    triggered_seen = bool(triggered_seen)
    if str(final_exit_reason or "").strip() == "post_green_protective_exit":
        triggered_seen = True
    if skipped_seen and triggered_seen:
        outcome = "SKIPPED_AND_TRIGGERED"
    elif triggered_seen:
        outcome = "TRIGGERED_ONLY"
    elif skipped_seen:
        outcome = "SKIPPED_ONLY"
    else:
        outcome = "NEITHER"
    skip_reason_val = None
    if last_skip_reason not in (None, "", "null", "None"):
        skip_reason_val = str(last_skip_reason)
    marker = {
        "post_green_protective_terminal_schema_version": 1,
        "post_green_protective_terminal_outcome": outcome,
        "post_green_protective_terminal_candidate_seen": candidate_seen,
        "post_green_protective_terminal_skip_seen": skipped_seen,
        "post_green_protective_terminal_trigger_seen": triggered_seen,
        "post_green_protective_terminal_last_skip_reason": skip_reason_val,
    }
    if isinstance(post_green_metrics, dict):
        marker["post_green_peak_mfe"] = post_green_metrics.get(
            "post_green_peak_mfe"
        )
        marker["post_green_time_since_peak_sec"] = post_green_metrics.get(
            "post_green_time_since_peak_sec"
        )
        marker["post_green_giveback_ratio"] = post_green_metrics.get(
            "post_green_giveback_ratio"
        )
        marker["post_green_exit_reason"] = post_green_metrics.get(
            "post_green_exit_reason"
        )
        marker["post_green_skip_reason"] = post_green_metrics.get(
            "post_green_skip_reason"
        )
        marker["post_green_trigger_mode"] = post_green_metrics.get(
            "post_green_trigger_mode"
        )
        marker["post_green_attempt_seq"] = post_green_metrics.get(
            "post_green_attempt_seq"
        )
        marker["post_green_branch_seq"] = post_green_metrics.get(
            "post_green_branch_seq"
        )
        marker["post_green_peak_to_burden_ratio"] = post_green_metrics.get(
            "post_green_peak_to_burden_ratio"
        )
        marker["post_green_bnr_time_forced_exit_sec"] = post_green_metrics.get(
            "post_green_bnr_time_forced_exit_sec"
        )
        marker["post_green_trigger_reason_detail"] = post_green_metrics.get(
            "post_green_trigger_reason_detail"
        )
        marker["post_green_rescue_exit_reason"] = post_green_metrics.get(
            "post_green_rescue_exit_reason"
        )
    return marker


def _paper_weak_peak_decay_decision(
    *,
    simulate,
    symbol,
    position,
    current_net_after_fee,
    fee_floor,
    pos_age_sec,
    paper_auto_close_sec,
    paper_auto_close_hard_sec=None,
    now_dt=None,
):
    # Keep hard-close as a fallback: prefer MFE/giveback/time-aware decay exits.
    stale_after_peak_sec = 35.0
    max_peak_fee_ratio = 1.20
    min_peak_fee_ratio = 0.20
    hard_window_min_peak_fee_ratio = 0.40
    min_giveback_ratio = 1.05
    hard_window_sec = 30.0
    hard_window_min_giveback_ratio = 1.20

    def _weak_peak_float(value):
        try:
            return float(value)
        except Exception:
            return None

    metrics = {
        "weak_peak_decay_candidate": False,
        "weak_peak_decay_triggered": False,
        "weak_peak_decay_reason": None,
        "weak_peak_decay_peak_mfe": None,
        "weak_peak_decay_fee_floor": None,
        "weak_peak_decay_peak_fee_ratio": None,
        "weak_peak_decay_max_peak_fee_ratio": max_peak_fee_ratio,
        "weak_peak_decay_min_peak_fee_ratio": min_peak_fee_ratio,
        "weak_peak_decay_giveback_ratio": None,
        "weak_peak_decay_min_giveback_ratio": min_giveback_ratio,
        "weak_peak_decay_time_since_peak_sec": None,
        "weak_peak_decay_time_until_hard_close_sec": None,
        "weak_peak_decay_hard_window_sec": hard_window_sec,
        "weak_peak_decay_hard_window_min_giveback_ratio": hard_window_min_giveback_ratio,
        "weak_peak_decay_hard_close_imminent": False,
        "weak_peak_decay_current_net_after_fee": None,
        "weak_peak_decay_stale_after_peak_sec": stale_after_peak_sec,
    }
    if not simulate:
        metrics["weak_peak_decay_reason"] = "not_paper_simulation"
        return False, "not_paper_simulation", metrics
    if not isinstance(position, dict):
        metrics["weak_peak_decay_reason"] = "position_unavailable"
        return False, "position_unavailable", metrics
    symbol_name = str(symbol or position.get("symbol") or "").strip().upper()
    open_snapshot = (
        position.get("open_snapshot")
        if isinstance(position.get("open_snapshot"), dict)
        else {}
    )
    if not (
        symbol_name.endswith("USDTM")
        and str(open_snapshot.get("source") or "") == "kucoin_futures_ticker"
    ):
        metrics["weak_peak_decay_reason"] = "not_kucoin_paper_symbol"
        return False, "not_kucoin_paper_symbol", metrics
    peak_mfe = position.get("mfe")
    if peak_mfe is None:
        peak_mfe = position.get("max_unrealized_pnl")
    peak_mfe = _weak_peak_float(peak_mfe)
    metrics["weak_peak_decay_peak_mfe"] = peak_mfe
    if peak_mfe is None or peak_mfe <= 0.0:
        metrics["weak_peak_decay_reason"] = "never_green"
        return False, "never_green", metrics
    current_net_val = _weak_peak_float(current_net_after_fee)
    metrics["weak_peak_decay_current_net_after_fee"] = current_net_val
    if current_net_val is None:
        metrics["weak_peak_decay_reason"] = "current_net_unavailable"
        return False, "current_net_unavailable", metrics
    if current_net_val >= 0.0:
        metrics["weak_peak_decay_reason"] = "current_net_nonnegative"
        return False, "current_net_nonnegative", metrics
    giveback_ratio = (float(peak_mfe) - float(current_net_val)) / float(peak_mfe)
    metrics["weak_peak_decay_giveback_ratio"] = giveback_ratio
    fee_floor_val = _weak_peak_float(fee_floor)
    metrics["weak_peak_decay_fee_floor"] = fee_floor_val
    if fee_floor_val is None or fee_floor_val <= 0.0:
        metrics["weak_peak_decay_reason"] = "fee_floor_unavailable"
        return False, "fee_floor_unavailable", metrics
    try:
        pos_age_val = float(pos_age_sec)
    except Exception:
        pos_age_val = None
    try:
        hard_close_gate = float(paper_auto_close_hard_sec)
    except Exception:
        hard_close_gate = None
    hard_close_imminent = False
    if (
        pos_age_val is not None
        and hard_close_gate is not None
        and hard_close_gate > 0.0
    ):
        time_until_hard = max(
            0.0,
            float(hard_close_gate) - float(pos_age_val),
        )
        metrics["weak_peak_decay_time_until_hard_close_sec"] = time_until_hard
        hard_close_imminent = time_until_hard <= float(hard_window_sec)
    metrics["weak_peak_decay_hard_close_imminent"] = bool(hard_close_imminent)
    peak_fee_ratio = float(peak_mfe) / float(fee_floor_val)
    metrics["weak_peak_decay_peak_fee_ratio"] = peak_fee_ratio
    effective_min_peak_fee_ratio = float(
        hard_window_min_peak_fee_ratio if hard_close_imminent else min_peak_fee_ratio
    )
    metrics["weak_peak_decay_min_peak_fee_ratio"] = effective_min_peak_fee_ratio
    if peak_fee_ratio < effective_min_peak_fee_ratio:
        metrics["weak_peak_decay_reason"] = "peak_too_weak_for_decay"
        return False, "peak_too_weak_for_decay", metrics
    if peak_fee_ratio >= float(max_peak_fee_ratio) and not (
        hard_close_imminent
        and giveback_ratio >= float(hard_window_min_giveback_ratio)
    ):
        metrics["weak_peak_decay_reason"] = "peak_above_fee_floor"
        return False, "peak_above_fee_floor", metrics
    peak_ts_raw = (
        position.get("peak_mfe_ts")
        or position.get("max_unrealized_pnl_ts")
        or position.get("first_positive_mfe_ts")
    )
    if peak_ts_raw in (None, ""):
        metrics["weak_peak_decay_reason"] = "peak_timestamp_unavailable"
        return False, "peak_timestamp_unavailable", metrics
    try:
        peak_dt = datetime.fromisoformat(str(peak_ts_raw).replace("Z", "+00:00"))
    except Exception:
        metrics["weak_peak_decay_reason"] = "peak_timestamp_unavailable"
        return False, "peak_timestamp_unavailable", metrics
    if peak_dt.tzinfo is None:
        peak_dt = peak_dt.replace(tzinfo=timezone.utc)
    if now_dt is None:
        now_dt = datetime.now(timezone.utc)
    if now_dt.tzinfo is None:
        now_dt = now_dt.replace(tzinfo=timezone.utc)
    time_since_peak_sec = max(0.0, (now_dt - peak_dt).total_seconds())
    metrics["weak_peak_decay_time_since_peak_sec"] = time_since_peak_sec
    if (not hard_close_imminent) and time_since_peak_sec < float(stale_after_peak_sec):
        metrics["weak_peak_decay_reason"] = "peak_not_stale"
        return False, "peak_not_stale", metrics
    if giveback_ratio < float(min_giveback_ratio):
        metrics["weak_peak_decay_reason"] = "giveback_below_trigger"
        return False, "giveback_below_trigger", metrics
    metrics["weak_peak_decay_candidate"] = True
    metrics["weak_peak_decay_triggered"] = True
    if peak_fee_ratio >= float(max_peak_fee_ratio):
        metrics["weak_peak_decay_reason"] = (
            "weak_peak_stale_decay_hard_window_feefloor_override"
        )
    elif hard_close_imminent:
        metrics["weak_peak_decay_reason"] = "weak_peak_stale_decay_hard_window"
    else:
        metrics["weak_peak_decay_reason"] = "weak_peak_stale_decay"
    return True, "triggered", metrics


def _classify_entry_reason(entry_reason):
    reason = str(entry_reason or "").strip()
    if reason == "current_side":
        return "position_hold"
    if reason == "loss_cooldown":
        return "cooldown_block"
    if reason in {
        "symbol_allowlist",
        "symbol_blocklist",
        "strategy_allowlist",
        "strategy_blocklist",
        "strategy_side_allowlist",
        "strategy_side_blocklist",
        "symbol_strategy_allowlist",
        "symbol_strategy_blocklist",
        "symbol_strategy_side_allowlist",
        "symbol_strategy_side_blocklist",
        "hysteresis",
        "buy_disabled",
        "sell_disabled",
        "weak_signal",
        "low_votes",
        "opposite_votes",
        "vote_dominance",
        "vote_delta",
        "trend_vol_filter_strict",
        "trend_vol_filter",
        "buy_score",
        "buy_trend",
        "buy_vol",
        "sell_trend",
        "range_low_vol",
        "entry_live_edge_proxy",
        "router_lead_filtered",
        "side_guard",
        "side_expectancy",
        "profit_gate",
        "profit_gate_exploration",
        "profit_focus_history_not_ready",
        "profit_focus_confidence_too_low",
        "tf_trend_entry_filtered",
        "net_target_guard",
        "rr_net_guard",
        "missing_strategy_field",
        "hold_ignored",
    }:
        if reason in {
            "symbol_allowlist",
            "symbol_blocklist",
            "strategy_allowlist",
            "strategy_blocklist",
            "strategy_side_allowlist",
            "strategy_side_blocklist",
            "symbol_strategy_allowlist",
            "symbol_strategy_blocklist",
            "symbol_strategy_side_allowlist",
            "symbol_strategy_side_blocklist",
            "weak_signal",
            "low_votes",
            "opposite_votes",
            "vote_dominance",
            "vote_delta",
            "trend_vol_filter_strict",
            "trend_vol_filter",
            "buy_score",
            "buy_trend",
            "buy_vol",
            "sell_trend",
            "range_low_vol",
            "entry_live_edge_proxy",
            "router_lead_filtered",
            "side_guard",
            "side_expectancy",
            "profit_gate",
            "profit_gate_exploration",
            "profit_focus_history_not_ready",
            "profit_focus_confidence_too_low",
            "tf_trend_entry_filtered",
            "net_target_guard",
            "rr_net_guard",
        }:
            return "risk_block"
        return "prefilter_block"
    if reason:
        return "unknown_fallback"
    return "unknown_fallback"


def _classify_entry_reason_with_gate_fallback(
    *, entry_reason=None, effective_gate_reason=None
):
    classification = _classify_entry_reason(entry_reason)
    if classification != "unknown_fallback":
        return classification
    gate_reason = _normalize_entry_reason(effective_gate_reason)
    if gate_reason in {None, "risk_or_prefilter_block_fallback", "unknown_fallback"}:
        return classification
    return _classify_entry_reason(gate_reason)


def _classify_entry_open_truth(
    selection_source=None,
    entry_reason=None,
    decision_router_path=None,
    override_reason=None,
):
    selection_source_norm = str(selection_source or "").strip().lower()
    entry_reason_norm = str(entry_reason or "").strip().lower()
    router_path_norm = str(decision_router_path or "").strip().lower()
    override_reason_norm = str(override_reason or "").strip().lower()

    if (
        selection_source_norm == "paper_auto_open_fallback"
        or router_path_norm == "paper_auto_open_fallback"
        or override_reason_norm == "paper_auto_open_fallback"
    ):
        return "PAPER_AUTO_OPEN_FALLBACK"

    if (
        selection_source_norm == "entry_symbol_strategy_side_allowlist"
        or router_path_norm == "paper_auto_open_allowlisted"
        or override_reason_norm == "paper_auto_open_allowlisted"
        or entry_reason_norm == "paper_auto_open_allowlisted"
    ):
        return "BOOTSTRAP_ALLOWLIST_ASSISTED"

    if entry_reason_norm == "seed_trades_override":
        return "SEED_TRADES_OVERRIDE_ASSISTED"

    if entry_reason_norm in {
        "edge_discovered_dynamic",
        "entry_live_edge",
        "live_edge_discovered",
        "dynamic_edge_discovered",
    }:
        return "EDGE_DISCOVERED_DYNAMIC"

    # Historical accepted corpora (e.g. Apr-11 replay) contain legacy position_close
    # payloads without entry_reason/selection_source fields. Absence of assisted markers
    # should be treated as natural strategy entry, not unknown.
    return "NATURAL_STRATEGY_ENTRY"


def _build_entry_identity_fields(
    *,
    symbol=None,
    strategy=None,
    side=None,
    selection_source=None,
    decision_router_path=None,
    entry_reason=None,
    override_reason=None,
):
    strategy_norm = str(strategy or "").strip() or None
    side_norm = str(side or "").strip().lower() or None
    canonical_bucket = build_canonical_bucket_key(
        {
            "symbol": symbol,
            "strategy": strategy_norm,
            "side": side_norm,
        }
    )
    return {
        "symbol": symbol,
        "strategy": strategy_norm,
        "entry_main_strategy": strategy_norm,
        "side": side_norm,
        "selection_source": selection_source,
        "decision_router_path": decision_router_path,
        "entry_reason": entry_reason,
        "override_reason": override_reason,
        "canonical_bucket": canonical_bucket,
        "canonical_bucket_key": canonical_bucket.get("canonical_bucket_key"),
    }


def _apply_symbol_strategy_guard_summary_identity(
    entry_gate_decision_summary,
    *,
    dropped_ensemble_signals=None,
):
    if not isinstance(entry_gate_decision_summary, dict):
        return entry_gate_decision_summary

    entry_gate_decision_summary.setdefault("blocked_candidate_strategy", None)
    entry_gate_decision_summary.setdefault("blocked_candidate_side", None)
    entry_gate_decision_summary.setdefault("blocked_candidate_entry_decision_raw", None)
    entry_gate_decision_summary.setdefault("blocked_candidate_source_reason", None)
    entry_gate_decision_summary.setdefault("blocked_candidate_identity_status", None)
    entry_gate_decision_summary.setdefault("blocked_candidate_identity_source", None)

    reason_norm = _normalize_entry_reason(
        entry_gate_decision_summary.get("local_gate_reason")
    )
    if reason_norm != "symbol_strategy_guard":
        return entry_gate_decision_summary

    def _normalize_guard_side(raw_value):
        try:
            side_text = str(raw_value or "").strip().lower()
        except Exception:
            side_text = ""
        if side_text in {"buy", "long", "1", "up"}:
            return "buy"
        if side_text in {"sell", "short", "-1", "down"}:
            return "sell"
        return None

    candidate_tuples = {}
    for dropped_payload in dropped_ensemble_signals or []:
        if not isinstance(dropped_payload, dict):
            continue
        dropped_reason = _normalize_entry_reason(dropped_payload.get("reason"))
        if dropped_reason != "symbol_strategy_guard":
            continue
        strategy_name = str(dropped_payload.get("strategy") or "").strip() or None
        side_name = _normalize_guard_side(
            dropped_payload.get("side") or dropped_payload.get("entry_decision_raw")
        )
        if strategy_name is None or side_name not in ("buy", "sell"):
            continue
        key = (strategy_name, side_name, side_name)
        candidate_tuples[key] = {
            "strategy": strategy_name,
            "side": side_name,
            "entry_decision_raw": side_name,
            "identity_status": "resolved",
            "identity_source": "dropped_ensemble_signals",
            "source_reason": "symbol_strategy_guard",
        }

    if not candidate_tuples:
        entry_gate_decision_summary["blocked_candidate_source_reason"] = (
            "symbol_strategy_guard"
        )
        entry_gate_decision_summary["blocked_candidate_identity_status"] = "unavailable"
        entry_gate_decision_summary["blocked_candidate_identity_source"] = (
            "dropped_ensemble_signals"
        )
        return entry_gate_decision_summary

    if len(candidate_tuples) == 1:
        blocked_identity = next(iter(candidate_tuples.values()))
        entry_gate_decision_summary["strategy"] = blocked_identity.get("strategy")
        entry_gate_decision_summary["main_strategy"] = blocked_identity.get("strategy")
        entry_gate_decision_summary["side"] = blocked_identity.get("side")
        entry_gate_decision_summary["entry_decision_raw"] = blocked_identity.get(
            "entry_decision_raw"
        )
        entry_gate_decision_summary["blocked_candidate_strategy"] = (
            blocked_identity.get("strategy")
        )
        entry_gate_decision_summary["blocked_candidate_side"] = (
            blocked_identity.get("side")
        )
        entry_gate_decision_summary["blocked_candidate_entry_decision_raw"] = (
            blocked_identity.get("entry_decision_raw")
        )
        entry_gate_decision_summary["blocked_candidate_source_reason"] = (
            blocked_identity.get("source_reason")
        )
        entry_gate_decision_summary["blocked_candidate_identity_status"] = (
            blocked_identity.get("identity_status")
        )
        entry_gate_decision_summary["blocked_candidate_identity_source"] = (
            blocked_identity.get("identity_source")
        )
        return entry_gate_decision_summary

    entry_gate_decision_summary["blocked_candidate_source_reason"] = (
        "symbol_strategy_guard"
    )
    entry_gate_decision_summary["blocked_candidate_identity_status"] = "ambiguous"
    entry_gate_decision_summary["blocked_candidate_identity_source"] = (
        "dropped_ensemble_signals"
    )
    return entry_gate_decision_summary


def _resolve_local_gate_reason(entry_reason, global_block_reason=None):
    if global_block_reason is not None:
        return str(global_block_reason)
    if entry_reason:
        return str(entry_reason)
    return "risk_or_prefilter_block_fallback"


def _has_strategy_alias_evidence(candidate_payload):
    if not isinstance(candidate_payload, dict):
        return False
    strategy_candidates = []
    for key in ("strategy", "main_strategy", "selected_strategy"):
        if key in candidate_payload:
            strategy_candidates.append(candidate_payload.get(key))
    signal_payload = candidate_payload.get("signal")
    if isinstance(signal_payload, dict):
        for key in ("strategy", "main_strategy", "selected_strategy"):
            if key in signal_payload:
                strategy_candidates.append(signal_payload.get(key))
    for value in strategy_candidates:
        try:
            strategy_text = str(value or "").strip()
        except Exception:
            strategy_text = ""
        if strategy_text and strategy_text.lower() not in {"none", "null"}:
            return True
    return False


def _derive_entry_reason_from_signal_funnel(
    *,
    entry_decision_raw=None,
    entry_decision_final=None,
    ensemble_signals=None,
    filtered_ensemble_signals=None,
    dropped_ensemble_signals=None,
):
    dropped_reason_set = set()
    if isinstance(dropped_ensemble_signals, (list, tuple)):
        for dropped_payload in dropped_ensemble_signals:
            if not isinstance(dropped_payload, dict):
                continue
            dropped_reason = _normalize_entry_reason(dropped_payload.get("reason"))
            if dropped_reason is not None:
                dropped_reason_set.add(dropped_reason)
    if (
        str(entry_decision_raw or "").strip().lower() == "hold"
        and str(entry_decision_final or "").strip().lower() == "hold"
        and bool(ensemble_signals)
        and not bool(filtered_ensemble_signals)
    ):
        preferred_dropped_reason = None
        if len(dropped_reason_set) == 1:
            preferred_dropped_reason = next(iter(dropped_reason_set))
        else:
            non_hold_reason_set = {
                dropped_reason
                for dropped_reason in dropped_reason_set
                if dropped_reason not in {"hold_ignored", "ambiguous_hold_side"}
            }
            if len(non_hold_reason_set) == 1:
                preferred_dropped_reason = next(iter(non_hold_reason_set))
        if preferred_dropped_reason == "missing_strategy":
            return "missing_strategy_field"
        if preferred_dropped_reason is not None:
            return preferred_dropped_reason
    return None


def _resolve_entry_policy_pipeline(
    *,
    symbol,
    decision_value,
    current_side,
    current_side_disabled,
    reverse_entry,
    now_ts,
    signal_score,
    ensemble_signals,
    filtered_ensemble_signals,
    dropped_ensemble_signals,
    last_decision_state,
    entry_symbol_allowlist,
    entry_symbol_blocklist,
    entry_allow_buy,
    entry_allow_sell,
    decision_hysteresis_score,
    decision_change_cooldown_sec,
):
    entry_decision = decision_value
    entry_reason = _derive_entry_reason_from_signal_funnel(
        entry_decision_raw=decision_value,
        entry_decision_final=decision_value,
        ensemble_signals=ensemble_signals,
        filtered_ensemble_signals=filtered_ensemble_signals,
        dropped_ensemble_signals=dropped_ensemble_signals,
    )

    if current_side and not current_side_disabled:
        return "hold", entry_reason or "current_side"

    if reverse_entry:
        return entry_decision, "reversal"

    if entry_decision in ("buy", "sell"):
        symbol_guard_key = str(symbol or "").strip().upper()
        if entry_symbol_allowlist and symbol_guard_key not in entry_symbol_allowlist:
            return "hold", "symbol_allowlist"
        if symbol_guard_key in entry_symbol_blocklist:
            return "hold", "symbol_blocklist"

        supporting_signal_found = False
        for signal_payload in filtered_ensemble_signals or []:
            if not isinstance(signal_payload, dict):
                continue
            side_value = str(
                signal_payload.get("_side") or signal_payload.get("side") or ""
            ).strip().lower()
            if side_value == entry_decision:
                supporting_signal_found = True
                break
        if not supporting_signal_found:
            return "hold", entry_reason or "no_supporting_signal"

        last_state = last_decision_state.get(symbol)
        if (
            last_state
            and decision_value != last_state.get("decision")
            and (
                abs(float(signal_score)) < decision_hysteresis_score
                or (now_ts - last_state.get("ts", 0.0))
                < decision_change_cooldown_sec
            )
        ):
            return "hold", "hysteresis"

        last_decision_state[symbol] = {
            "decision": decision_value,
            "ts": now_ts,
        }

    if entry_decision == "buy" and not entry_allow_buy:
        return "hold", "buy_disabled"
    if entry_decision == "sell" and not entry_allow_sell:
        return "hold", "sell_disabled"

    return entry_decision, entry_reason


def _apply_side_profit_edge_gate_pipeline(
    *,
    entry_decision,
    entry_reason,
    gate_blocked,
    gate_reason,
):
    if entry_decision not in ("buy", "sell") or not bool(gate_blocked):
        return entry_decision, entry_reason
    normalized_reason = _normalize_entry_reason(gate_reason)
    if normalized_reason is None:
        normalized_reason = str(gate_reason or "").strip() or None
    return "hold", (entry_reason or normalized_reason)


def _set_entry_reason_if_unset(entry_reason, candidate_reason):
    normalized_reason = _normalize_entry_reason(candidate_reason)
    if normalized_reason is None:
        normalized_reason = str(candidate_reason or "").strip() or None
    return entry_reason or normalized_reason


def _normalize_local_gate_reason_for_summary(
    *,
    local_gate_reason,
    entry_reason=None,
    main_strategy=None,
    entry_decision_raw=None,
    entry_decision_final=None,
    ensemble_signals=None,
    filtered_ensemble_signals=None,
    dropped_ensemble_signals=None,
    bucket_identity_reason=None,
):
    try:
        reason = str(local_gate_reason or "").strip()
    except Exception:
        return local_gate_reason
    if reason != "risk_or_prefilter_block_fallback":
        return reason or local_gate_reason

    entry_reason_norm = str(entry_reason or "").strip().lower()
    bucket_identity_reason_norm = str(bucket_identity_reason or "").strip().lower()
    main_strategy_missing = main_strategy is None
    if not main_strategy_missing:
        try:
            main_strategy_norm = str(main_strategy or "").strip().lower()
        except Exception:
            main_strategy_norm = ""
        main_strategy_missing = main_strategy_norm in {"", "none", "null"}
    if entry_reason_norm in {"", "none", "null"}:
        derived_reason = _derive_entry_reason_from_signal_funnel(
            entry_decision_raw=entry_decision_raw,
            entry_decision_final=entry_decision_final,
            ensemble_signals=ensemble_signals,
            filtered_ensemble_signals=filtered_ensemble_signals,
            dropped_ensemble_signals=dropped_ensemble_signals,
        )
        if derived_reason is not None:
            return derived_reason
        if (
            bucket_identity_reason_norm == "missing_strategy_field"
            and main_strategy_missing
            and str(entry_decision_raw or "").strip().lower() == "hold"
            and str(entry_decision_final or "").strip().lower() == "hold"
            and not bool(ensemble_signals)
            and not bool(filtered_ensemble_signals)
            and not bool(dropped_ensemble_signals)
        ):
            return "missing_strategy_field"
        strategy_alias_present = False
        if isinstance(ensemble_signals, (list, tuple)):
            for candidate_payload in ensemble_signals:
                if _has_strategy_alias_evidence(candidate_payload):
                    strategy_alias_present = True
                    break
        if (
            main_strategy_missing
            and str(entry_decision_raw or "").strip().lower() == "hold"
            and str(entry_decision_final or "").strip().lower() == "hold"
            and bool(ensemble_signals)
            and not bool(filtered_ensemble_signals)
            and not strategy_alias_present
        ):
            return "missing_strategy_field"
    return reason


def _normalize_entry_reason(reason):
    try:
        reason_norm = str(reason).strip()
    except Exception:
        return None
    if reason_norm in ("", "null", "None", "none"):
        return None
    return reason_norm


def _canonical_bucket_trace_for_summary(entry_gate_decision_summary):
    if not isinstance(entry_gate_decision_summary, dict):
        return {}
    canonical_bucket_trace = entry_gate_decision_summary.get("canonical_bucket")
    if isinstance(canonical_bucket_trace, dict):
        return canonical_bucket_trace
    return {}


def _should_fail_closed_unknown_fallback_admission(
    *,
    simulate,
    market_type,
    allow,
    entry_decision,
    entry_reason,
    signal_confidence_abs=None,
    history_ready=None,
    coldstart_mode=None,
    min_signal_confidence_abs=0.55,
):
    if not bool(allow):
        return False
    decision_norm = str(entry_decision or "").strip().lower()
    if decision_norm not in {"buy", "sell"}:
        return False
    if not bool(simulate):
        return False
    if str(market_type or "").strip().lower() != "futures":
        return False
    reason_norm = str(entry_reason or "").strip().lower()
    if reason_norm in {
        "seed_trades_override",
        "insufficient_history_seed_only",
        "insufficient_history_fail_open",
    }:
        return False
    if _classify_entry_reason(entry_reason) != "unknown_fallback":
        return False
    try:
        confidence_abs = float(signal_confidence_abs)
    except Exception:
        confidence_abs = None
    if history_ready is False:
        if coldstart_mode is not None and not _should_fail_closed_on_history_not_ready(
            coldstart_mode
        ):
            return False
        if confidence_abs is None:
            return True
        return confidence_abs < float(min_signal_confidence_abs)
    if confidence_abs is None:
        return True
    return confidence_abs < float(min_signal_confidence_abs)


def _resolve_entry_gate_reason_context(
    *,
    global_block_reason=None,
    local_gate_reason=None,
    entry_reason=None,
):
    global_reason_norm = _normalize_entry_reason(global_block_reason)
    if global_reason_norm is not None:
        return {
            "effective_gate_reason": global_reason_norm,
            "effective_gate_reason_origin": "global_block_reason",
        }
    local_reason_norm = _normalize_entry_reason(local_gate_reason)
    if local_reason_norm is not None:
        return {
            "effective_gate_reason": local_reason_norm,
            "effective_gate_reason_origin": "local_gate_reason",
        }
    entry_reason_norm = _normalize_entry_reason(entry_reason)
    if entry_reason_norm is not None:
        return {
            "effective_gate_reason": entry_reason_norm,
            "effective_gate_reason_origin": "entry_reason",
        }
    return {
        "effective_gate_reason": "risk_or_prefilter_block_fallback",
        "effective_gate_reason_origin": "fallback",
    }


def _resolve_summary_fallback_attribution(
    *,
    effective_gate_reason,
    local_gate_reason,
    entry_reason=None,
    final_prefilter_reason=None,
    entry_decision_raw=None,
    entry_decision_final=None,
    ensemble_signals=None,
    filtered_ensemble_signals=None,
    dropped_ensemble_signals=None,
):
    original_effective = _normalize_entry_reason(effective_gate_reason)
    original_local = _normalize_entry_reason(local_gate_reason)
    fallback_markers = {"risk_or_prefilter_block_fallback", "unknown_fallback", None}
    allowed_predicates = {
        "weak_signal",
        "low_votes",
        "opposite_votes",
        "range_low_vol",
        "buy_trend",
        "side_guard",
        "hold_ignored",
        "ambiguous_hold_side",
    }

    if original_effective not in fallback_markers:
        return {
            "effective_gate_reason": original_effective,
            "local_gate_reason": original_local,
            "resolved_upstream_predicate": original_effective,
            "resolved_upstream_source": "effective_gate_reason",
            "attribution_resolution_applied": False,
            "original_effective_gate_reason": original_effective,
            "original_local_gate_reason": original_local,
        }

    candidates = []
    prefilter_norm = _normalize_entry_reason(final_prefilter_reason)
    if prefilter_norm in allowed_predicates:
        candidates.append((prefilter_norm, "final_prefilter_reason"))

    derived_reason = _derive_entry_reason_from_signal_funnel(
        entry_decision_raw=entry_decision_raw,
        entry_decision_final=entry_decision_final,
        ensemble_signals=ensemble_signals,
        filtered_ensemble_signals=filtered_ensemble_signals,
        dropped_ensemble_signals=dropped_ensemble_signals,
    )
    derived_norm = _normalize_entry_reason(derived_reason)
    if derived_norm in allowed_predicates:
        candidates.append((derived_norm, "signal_funnel_dropped_reasons"))

    local_norm = _normalize_entry_reason(local_gate_reason)
    if local_norm in allowed_predicates:
        candidates.append((local_norm, "local_gate_reason"))

    entry_norm = _normalize_entry_reason(entry_reason)
    if entry_norm in allowed_predicates:
        candidates.append((entry_norm, "entry_reason"))

    if candidates:
        resolved_reason, resolved_source = candidates[0]
        return {
            "effective_gate_reason": resolved_reason,
            "local_gate_reason": (
                resolved_reason if local_norm in fallback_markers else local_norm
            ),
            "resolved_upstream_predicate": resolved_reason,
            "resolved_upstream_source": resolved_source,
            "attribution_resolution_applied": True,
            "original_effective_gate_reason": original_effective,
            "original_local_gate_reason": original_local,
        }

    return {
        "effective_gate_reason": original_effective,
        "local_gate_reason": original_local,
        "resolved_upstream_predicate": "attribution_loss_no_upstream_reason",
        "resolved_upstream_source": "none",
        "attribution_resolution_applied": False,
        "original_effective_gate_reason": original_effective,
        "original_local_gate_reason": original_local,
    }


def _classify_entry_gate_bucket(
    *,
    final_allow,
    effective_gate_reason,
    effective_gate_reason_origin,
    research_block_active=False,
):
    if bool(final_allow):
        return "admitted"
    if bool(research_block_active):
        return "research_loss_driver_block"
    if str(effective_gate_reason_origin or "") == "global_block_reason":
        return "global_gate_block"

    reason_norm = str(effective_gate_reason or "").strip().lower()
    if reason_norm in {
        "insufficient_history_seed_only",
        "insufficient_history_fail_open",
        "seed_trades_override",
    }:
        return "history_coldstart"
    if reason_norm in {
        "entry_edge_filtered",
        "trend_mixed_edge_over_fee_gate",
        "momentum_mixed_expected_edge_after_execution_gate",
        "momentum_mixed_never_green_filter",
        "net_target_guard",
        "rr_net_guard",
        "tf_trend_entry_filtered",
        "entry_live_edge_proxy",
    }:
        return "economics_or_quality_guard"
    if reason_norm in {
        "current_side",
        "side_guard",
        "side_expectancy",
    }:
        return "position_side_guard"
    if reason_norm in {
        "loss_cooldown",
        "profit_gate",
        "profit_gate_exploration",
    }:
        return "cooldown_guard"
    if (
        reason_norm.endswith("allowlist")
        or reason_norm.endswith("blocklist")
        or reason_norm
        in {
            "hysteresis",
            "buy_disabled",
            "sell_disabled",
            "weak_signal",
            "low_votes",
            "opposite_votes",
            "vote_dominance",
            "vote_delta",
            "trend_vol_filter_strict",
            "trend_vol_filter",
            "buy_score",
            "buy_trend",
            "buy_vol",
            "sell_trend",
            "range_low_vol",
            "router_lead_filtered",
        }
    ):
        return "prefilter_guard"
    if reason_norm in {"risk_or_prefilter_block_fallback", "unknown_fallback"}:
        return "fallback_guard"
    return "other_local_guard"


def apply_ai_vote(signal_score, signal_votes, ai_pred, weight):
    if weight is None or weight <= 0 or ai_pred is None:
        return signal_score, signal_votes, None
    try:
        pred_int = int(ai_pred)
    except Exception:
        return signal_score, signal_votes, None
    side = "buy" if pred_int == 1 else "sell"
    signal_votes.append(
        {
            "strategy": "OnlineTrainer",
            "side": side,
            "allocation": weight,
        }
    )
    return signal_score, signal_votes, side


def apply_meta_vote(signal_score, signal_votes, strategy_name, side, weight):
    if weight is None or weight <= 0 or not strategy_name:
        return signal_score, signal_votes, None
    if side not in ("buy", "sell"):
        return signal_score, signal_votes, None
    if side == "buy":
        signal_score += weight
    else:
        signal_score -= weight
    signal_votes.append(
        {
            "strategy": f"MetaRouter:{strategy_name}",
            "side": side,
            "allocation": weight,
        }
    )
    return signal_score, signal_votes, side


def _attach_fl_trend_payload_fields(
    decision_payload,
    *,
    fl_trend_hint,
    fl_trend_override_counts,
    symbol,
):
    if not isinstance(decision_payload, dict):
        return decision_payload
    decision_payload["fl_trend_hint"] = fl_trend_hint
    decision_payload["fl_base_pred"] = (
        fl_trend_hint.get("base_pred") if isinstance(fl_trend_hint, dict) else None
    )
    decision_payload["fl_trend_override_applied"] = bool(
        isinstance(fl_trend_hint, dict) and fl_trend_hint.get("applied")
    )
    decision_payload["fl_trend_override_direction"] = (
        fl_trend_hint.get("direction") if isinstance(fl_trend_hint, dict) else None
    )
    decision_payload["fl_trend_override_count_symbol"] = int(
        (fl_trend_override_counts or {}).get(symbol) or 0
    )
    return decision_payload


def _extract_federated_close_values(candles):
    close_values = []
    for candle in candles or []:
        if not isinstance(candle, dict):
            continue
        try:
            close_values.append(float(candle["close"]))
        except Exception:
            continue
    return close_values


def _build_federated_round_inputs(
    candles,
    max_clients=3,
    min_client_size=5,
    min_holdout_size=4,
):
    close_values = _extract_federated_close_values(candles)
    if len(close_values) < (min_client_size + min_holdout_size):
        return [], []

    holdout_size = min(
        max(min_holdout_size, len(close_values) // 5),
        len(close_values) - min_client_size,
    )
    train_values = close_values[:-holdout_size]
    holdout = close_values[-holdout_size:]
    if len(train_values) < min_client_size or len(holdout) < min_holdout_size:
        return [], []

    client_count = max(1, min(max_clients, len(train_values) // min_client_size))
    chunk_size = max(min_client_size, len(train_values) // client_count)
    clients = []
    for start in range(0, len(train_values), chunk_size):
        chunk = train_values[start : start + chunk_size]
        if len(chunk) >= min_client_size:
            clients.append({"data": chunk})
        if len(clients) >= client_count:
            break

    if not clients:
        return [], []
    return clients, holdout


def maybe_run_federated_learning(
    federated_round,
    fl_round_limit,
    symbol,
    candles,
    trend_predictor,
    infinity_logger,
    logger=None,
):
    if fl_round_limit <= 0 or federated_round % fl_round_limit != 0:
        return False

    logger = logger or __import__("logging").getLogger("zol0.botcore")

    try:
        from fl.runner import run_fl_round

        clients, holdout = _build_federated_round_inputs(candles)
        if not clients:
            logger.info(
                "BotCore: FL round skipped for %s (insufficient candle history).",
                symbol,
            )
            return False

        prev_global = getattr(trend_predictor, "federated_global_model", None)
        fl_research_only = True
        try:
            fl_research_only = _env_flag("FL_RESEARCH_ONLY", "1")
        except Exception:
            fl_research_only = True
        proposed_global = run_fl_round(
            clients,
            prev_global,
            holdout=holdout,
        )
        if fl_research_only:
            applied_global = prev_global
            logger.info(
                "BotCore: FL round ran in research-only mode for %s.",
                symbol,
            )
        else:
            applied_global = trend_predictor.federated_update(
                proposed_global,
                holdout=holdout,
            )
        payload = {
            "step": federated_round,
            "symbol": symbol,
            "clients": len(clients),
            "holdout_size": len(holdout),
            "mode": "research_only" if fl_research_only else "execution",
            "proposed_global_model": proposed_global,
            "global_model": applied_global,
        }
        try:
            infinity_logger.log("fl_round", payload)
        except Exception:
            logger.warning("BotCore: FL event logging failed for %s", symbol)
        logger.info("BotCore: FL round complete for %s.", symbol)
        return True
    except Exception as exc:
        logger.warning("BotCore: FL round failed for %s: %s", symbol, exc)
        return False


def run_bot(simulate=False):
    """
    Production-grade main bot logic with full error handling and ML.
    """
    if simulate:
        _reset_simulated_run_in_memory_state()

    def _ensure_kucoin_url(url, label):
        if url and "kucoin.com" not in str(url).lower():
            raise ValueError(f"{label}: non-KuCoin api_url blocked (NO-GO)")

    # Setup config, logger, and all required components
    # [TASK-ID: logic_guard]
    # ⚠️ UWAGA: poniższa pętla jest krytyczna dla czasu decyzji –
    # żadnych operacji I/O, sleep, ani monitoringu!
    # @no_slow_path
    # ⬆️ optimized for performance:
    # cache config, logger, and model objects outside the main loop
    config = load_config(_resolve_repo_config_path())
    setup_logger()
    import logging

    logger = logging.getLogger("zol0.botcore")
    import time
    import os
    import random
    import pandas as pd
    import numpy as np
    import uuid
    import bisect
    from datetime import datetime, timezone, timedelta
    from security.live_guard import is_live_armed
    from utils.paper_gate import update_gate
    from core.db_models import SessionLocal, Equity, LogEntry
    from core.InfinityLayerLogger import InfinityLayerLogger
    from ai.OnlineTrainer import OnlineTrainer
    from core.MarketDataFetcher import MarketDataFetcher
    from core.OrderExecutor import OrderExecutor
    from core.paper_quote_source import fetch_kucoin_paper_quote
    from core.RiskManager import RiskManager
    from core.StrategyPerformanceTracker import StrategyPerformanceTracker
    from core.PositionManager import PositionManager
